export const TOPICS_C = [
  // ── TK–2 ───────────────────────────────────────────────────────────────────
  { id:'number-bonds', title:'Number Bonds', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['number bonds','part part whole','addition facts','decompose'], summary:'Break numbers into parts to build addition and subtraction fluency.', intro:'A number bond shows a whole and its two parts. 10 = 6 + 4.', steps:[{title:'Whole and parts',body:'Draw two circles (parts) connected to one large circle (whole).'},{title:'Find missing part',body:'8 = 5 + ? → ?=3. Use subtraction: 8-5=3.'},{title:'Make 10',body:'Learn pairs that sum to 10: 1+9, 2+8, 3+7, 4+6, 5+5.'},{title:'Use for mental math',body:'To add 7+6: break 6=3+3. 7+3=10, then +3=13.'}], explanation:'Number bonds to 10 and 20 form the mental math toolkit for arithmetic.', exercises:[{question:'8 = 3 + ?',answer:'5',hint:'8-3=5.'},{question:'Find a number bond for 15.',answer:'e.g., 7+8=15',hint:'Many answers work.'},{question:'Use bonds to add 8+7.',answer:'15 (8+2+5=15)',hint:'Break 7 into 2+5.'}]},
  { id:'multiplication-arrays', title:'Multiplication Arrays', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['array','rows','columns','multiplication','area model'], summary:'Use arrays (rows and columns) to understand multiplication.', intro:'An array is an organized grid of objects in rows and columns that models multiplication.', steps:[{title:'Rows × columns',body:'3 rows × 4 columns = 12 objects total. 3×4=12.'},{title:'Commutative property',body:'3×4 = 4×3: rotate the array 90° and get 4 rows × 3 columns, same total.'},{title:'Area model',body:'A 3×4 rectangle has area=12 square units, same as 3×4=12.'},{title:'Find factor from array',body:'Array shows 5 rows and ? columns. Count a row to find columns.'}], explanation:'Arrays link multiplication to area and build spatial reasoning.', exercises:[{question:'Array: 4 rows, 6 cols. Total?',answer:'24',hint:'4×6=24.'},{question:'Draw an array for 3×7.',answer:'3 rows, 7 columns',hint:'Rows × columns.'},{question:'Array 6×9. Rotate. New dimensions?',answer:'9 rows × 6 cols = same 54',hint:'Commutative.'}]},
  { id:'fractions-thirds-fifths', title:'Thirds, Fourths and Fifths', grade:'tk2', gradeLabel:'TK–2', subject:'fractions', tags:['thirds','fourths','fifths','equal parts','fraction'], summary:'Understand and identify fractions with denominators 3, 4, and 5.', intro:'When we split a whole into equal parts, each part gets a fraction name.', steps:[{title:'Thirds',body:'3 equal parts. Each part = 1/3. Example: pizza cut into 3 equal slices.'},{title:'Fourths',body:'4 equal parts = 1/4 each.'},{title:'Fifths',body:'5 equal parts = 1/5 each.'},{title:'Comparison',body:'1/3 > 1/4 > 1/5. More pieces = smaller each.'}], explanation:'The more equal parts, the smaller each part. This is the inverse relationship in fractions.', exercises:[{question:'Rectangle cut into 5 equal parts. You shade 3. Fraction?',answer:'3/5',hint:'Numerator = shaded, denominator = total.'},{question:'Which is bigger: 1/3 or 1/5?',answer:'1/3',hint:'Fewer pieces = larger each.'},{question:'What fraction of a week is 3 days?',answer:'3/7',hint:'7 days in a week.'}]},
  { id:'word-problems-addition-subtraction', title:'Addition & Subtraction Word Problems', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['word problems','add','subtract','story problems'], summary:'Solve simple addition and subtraction story problems.', intro:'Word problems describe real situations. Your job is to translate the story into a math equation.', steps:[{title:'Read and retell',body:'Read the problem, then retell it in your own words.'},{title:'Identify clue words',body:'"How many in all/together/total" → add. "How many left/fewer/remain" → subtract.'},{title:'Write the equation',body:'5 birds + 3 birds = 8 birds.'},{title:'Check units',body:'Does the answer use the right unit? (birds, apples, etc.)'}], explanation:'Story problems build mathematical communication and real-world reasoning.', exercises:[{question:'12 apples. Ate 5. How many left?',answer:'7',hint:'12-5=7.'},{question:'9 boys and 7 girls in class. Total?',answer:'16',hint:'9+7=16.'},{question:'Had $8, earned $5 more. Total?',answer:'$13',hint:'8+5=13.'}]},
  { id:'counting-on-counting-back', title:'Counting On and Counting Back', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['counting on','counting back','mental math','addition','subtraction'], summary:'Add by counting on and subtract by counting back from a starting number.', intro:'Counting on starts at the larger number and counts up. Counting back starts at the larger and counts down.', steps:[{title:'Counting on',body:'5+3: start at 5, count on 3: 6,7,8. Answer: 8.'},{title:'Always start at bigger number',body:'3+8: start at 8 (bigger), count on 3: 9,10,11.'},{title:'Counting back',body:'9-4: start at 9, count back 4: 8,7,6,5. Answer: 5.'},{title:'Use fingers',body:'Raise a finger for each count.'}], explanation:'These strategies bridge the gap between concrete counting and mental math fluency.', exercises:[{question:'Count on: 7+4=?',answer:'11',hint:'Start at 7, count 8,9,10,11.'},{question:'Count back: 11-3=?',answer:'8',hint:'Start at 11, count 10,9,8.'},{question:'6+8=? (start at bigger)',answer:'14',hint:'Start 8, count on 6 more.'}]},
  { id:'making-ten', title:'Making Ten Strategy', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['make ten','bridge ten','addition strategy','mental math'], summary:'Add numbers by first making a ten, then adding the rest.', intro:'Because ten is easy to work with, breaking addition into "make ten first" speeds computation.', steps:[{title:'Find what makes 10',body:'9+5: 9 needs 1 more to make 10. Take 1 from 5.'},{title:'Make ten',body:'9+1=10. Remaining: 5-1=4.'},{title:'Add remainder',body:'10+4=14. So 9+5=14.'},{title:'Practice',body:'8+6: 8+2=10, 6-2=4. 10+4=14.'}], explanation:'The make-ten strategy is the foundation of mental addition and borrowing in written addition.', exercises:[{question:'7+6=? (make ten first)',answer:'13',hint:'7+3=10, 6-3=3. 10+3=13.'},{question:'9+7=? (make ten)',answer:'16',hint:'9+1=10, 7-1=6. 10+6=16.'},{question:'8+5=?',answer:'13',hint:'8+2=10, 5-2=3. 10+3=13.'}]},
  { id:'less-than-more-than', title:'More Than, Less Than, Equal To', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['more than','less than','equal to','compare','>','<','='], summary:'Compare groups and numbers using more than, less than, and equal to.', intro:'We compare to decide which quantity is bigger, smaller, or the same.', steps:[{title:'Count and compare',body:'Group A: 7 blocks. Group B: 5 blocks. 7 > 5. Group A has more.'},{title:'Symbol language',body:'> = greater than. < = less than. = = equal to.'},{title:'The open mouth rule',body:'The open mouth (alligator mouth) always faces the bigger number.'},{title:'Apply to expressions',body:'3+4 __ 6+1 → 7 __ 7 → 7=7.'}], explanation:'Comparison is the foundation of ordering, ranking, and understanding magnitude.', exercises:[{question:'12 __ 9',answer:'>',hint:'12 is bigger.'},{question:'5+3 __ 4+4',answer:'=',hint:'Both equal 8.'},{question:'Order: 14, 9, 22, 7.',answer:'7,9,14,22',hint:'Smallest to largest.'}]},
  { id:'addition-facts-to-20', title:'Addition Facts to 20', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['addition facts','fluency','mental math','sums to 20'], summary:'Build fluency with all addition facts with sums up to 20.', intro:'Knowing addition facts by heart frees your brain for more complex thinking.', steps:[{title:'Use ten frames',body:'Fill a ten frame. Extra tiles go in the second frame. Visual fact.'},{title:'Doubles',body:'5+5=10, 6+6=12, 7+7=14, 8+8=16, 9+9=18.'},{title:'Near doubles',body:'7+8: know 7+7=14. One more → 15.'},{title:'Facts with 9',body:'9+6: move 1 from 6 to 9 → 10+5=15.'}], explanation:'Fluency by end of grade 2 is a research-backed milestone that predicts later math success.', exercises:[{question:'9+8=?',answer:'17',hint:'9+8: 10+7=17.'},{question:'7+6=?',answer:'13',hint:'Near double: 7+7-1=13.'},{question:'8+8=?',answer:'16',hint:'Double 8.'}]},
  { id:'subtraction-facts-to-20', title:'Subtraction Facts to 20', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['subtraction facts','fluency','think addition','mental math'], summary:'Build subtraction fluency to 20 using addition fact families.', intro:'Subtraction and addition facts come in families. Knowing one gives you three others.', steps:[{title:'Fact families',body:'3+7=10, 7+3=10, 10-3=7, 10-7=3. One family, four facts.'},{title:'Think addition',body:'14-8=?: 8+?=14. Answer: 6.'},{title:'Count up strategy',body:'13-7: start at 7, count up to 13: 7→13 is 6 jumps.'},{title:'Fluency goal',body:'Instant recall within 3 seconds.'}], explanation:'Thinking of subtraction as "missing addend" ties it permanently to addition facts.', exercises:[{question:'15-7=?',answer:'8',hint:'7+8=15.'},{question:'18-9=?',answer:'9',hint:'9+9=18.'},{question:'12-5=?',answer:'7',hint:'5+7=12.'}]},
  { id:'geometry-positions', title:'Positional Words & Geometry', grade:'tk2', gradeLabel:'TK–2', subject:'geometry', tags:['position','above','below','beside','between','left right'], summary:'Use positional words to describe the location of objects.', intro:'Positional words describe where things are relative to each other.', steps:[{title:'Key words',body:'Above, below, beside, between, left, right, inside, outside, near, far, on top, under.'},{title:'Relative position',body:'"The cat is beside the box" — position changes if you move the reference object.'},{title:'Left/Right',body:'Left is the side where your heart is. Right is the other side.'},{title:'Geometry connection',body:'Understanding positions helps with coordinates, maps, and diagrams.'}], explanation:'Spatial language predicts early geometry success and real-world navigation ability.', exercises:[{question:'Book is above the table. What is below the book?',answer:'The table',hint:'They are directly opposite.'},{question:'Describe position: "ball is ___ the cup and the box."',answer:'Between',hint:'Located in the middle of two objects.'},{question:'Draw a circle to the left of a square.',answer:'Circle | Square (left to right)',hint:'Left comes before right.'}]},

  // ── Grades 3–5 ─────────────────────────────────────────────────────────────
  { id:'multiplication-of-fractions-whole', title:'Fractions Times Whole Numbers', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['fraction times whole','multiply','repeated addition'], summary:'Multiply a fraction by a whole number using repeated addition.', intro:'4 × 2/3 means four groups of 2/3. It is repeated addition of fractions.', steps:[{title:'Rewrite as repeated addition',body:'4 × 2/3 = 2/3+2/3+2/3+2/3 = 8/3.'},{title:'Shortcut: multiply numerator',body:'4 × 2/3 = (4×2)/3 = 8/3.'},{title:'Simplify',body:'8/3 = 2⅔.'},{title:'Real context',body:'3 recipes each needing ¾ cup: 3×3/4=9/4=2¼ cups.'}], explanation:'Multiplying a fraction by a whole number is the first step toward full fraction multiplication.', exercises:[{question:'5 × 3/4=?',answer:'15/4 = 3¾',hint:'5×3=15. Over 4.'},{question:'6 × 2/5=?',answer:'12/5 = 2⅖',hint:'6×2=12. Over 5.'},{question:'Recipe needs ⅔ cup. Triple it.',answer:'2 cups',hint:'3×2/3=6/3=2.'}]},
  { id:'geometry-quadrilaterals', title:'Quadrilaterals', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['quadrilateral','parallelogram','rhombus','trapezoid','rectangle','square'], summary:'Identify and classify quadrilaterals by their properties.', intro:'A quadrilateral has 4 sides and 4 angles. Each type has special properties.', steps:[{title:'Hierarchy',body:'All squares are rectangles. All rectangles are parallelograms. All are quadrilaterals.'},{title:'Parallelogram',body:'2 pairs of parallel sides. Opposite sides equal.'},{title:'Rectangle',body:'Parallelogram with 4 right angles.'},{title:'Rhombus',body:'Parallelogram with 4 equal sides.'},{title:'Square',body:'Rectangle AND rhombus: 4 equal sides + 4 right angles.'},{title:'Trapezoid',body:'Exactly 1 pair of parallel sides (US definition).'}], explanation:'The quadrilateral family tree helps you derive all properties from the definition.', exercises:[{question:'Sides all equal, no right angles. Name.',answer:'Rhombus',hint:'All sides equal but not a square.'},{question:'All rectangles are also __.',answer:'Parallelograms',hint:'A rectangle has 2 pairs of parallel sides.'},{question:'Trapezoid has how many pairs of parallel sides?',answer:'1',hint:'By definition.'}]},
  { id:'data-mean-from-data', title:'Finding Mean from a Data Set', grade:'35', gradeLabel:'3–5', subject:'statistics', tags:['mean','average','data','sum','divide'], summary:'Calculate the mean (average) by dividing the sum by the count.', intro:'The mean balances a data set — like finding where all data points balance on a seesaw.', steps:[{title:'Add all values',body:'Data: 3, 7, 5, 9, 1. Sum = 25.'},{title:'Count the values',body:'5 values total.'},{title:'Divide sum by count',body:'25 ÷ 5 = 5. Mean = 5.'},{title:'Interpret',body:'Mean=5: the data balances at 5.'}], explanation:'The mean is the fair-share value — if all values were equal, each would equal the mean.', exercises:[{question:'Data: 8, 12, 4, 16. Mean?',answer:'10',hint:'40÷4=10.'},{question:'Mean of 6, 6, 6, 6?',answer:'6',hint:'All same = mean.'},{question:'Mean=7 for 3 values. Two values are 5 and 9. Third?',answer:'7',hint:'Sum=21. 21-5-9=7.'}]},
  { id:'number-line-fractions', title:'Number Line: Fractions and Mixed Numbers', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['number line','fractions','mixed numbers','plot'], summary:'Plot fractions and mixed numbers on a number line.', intro:'Number lines extend beyond 0 and 1 to show all rational numbers.', steps:[{title:'Whole number sections',body:'Divide number line into segments 0-1, 1-2, 2-3 etc.'},{title:'Divide each section',body:'For thirds: divide each whole-number segment into 3 equal parts.'},{title:'Plot fractions',body:'5/3 = 1⅔. Plot between 1 and 2, 2/3 of the way.'},{title:'Compare',body:'Numbers further right are greater. 7/4 > 5/4.'}], explanation:'The number line unifies whole numbers, fractions, and decimals into one system.', exercises:[{question:'Plot 7/4 on a number line.',answer:'Between 1 and 2, at the 3/4 mark',hint:'7/4=1¾.'},{question:'Which is greater: 8/5 or 3/2?',answer:'8/5=1.6 > 3/2=1.5',hint:'Convert to decimals.'},{question:'What fraction is halfway between 0 and 1/4?',answer:'1/8',hint:'1/2 of 1/4.'}]},
  { id:'units-of-time-conversion', title:'Converting Units of Time', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['time','convert','seconds','minutes','hours','days','weeks'], summary:'Convert between seconds, minutes, hours, days, weeks, and months.', intro:'Time units have fixed conversion factors to memorize.', steps:[{title:'Unit chain',body:'60 s = 1 min. 60 min = 1 hr. 24 hr = 1 day. 7 days = 1 week. 52 weeks ≈ 1 year.'},{title:'Convert to smaller',body:'3 hours = 3×60=180 minutes.'},{title:'Convert to larger',body:'180 seconds ÷ 60 = 3 minutes.'},{title:'Multi-step',body:'2.5 hours = 2×60+30=150 minutes.'}], explanation:'Time is the only non-metric measurement system still used universally.', exercises:[{question:'3.5 minutes = ? seconds',answer:'210 seconds',hint:'3.5×60=210.'},{question:'3 weeks = ? days',answer:'21 days',hint:'3×7=21.'},{question:'2 hours 45 minutes = ? minutes',answer:'165 minutes',hint:'120+45=165.'}]},
  { id:'area-with-fractions', title:'Area with Fractional Lengths', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['area','fractions','rectangle','half unit'], summary:'Calculate area of rectangles with fractional side lengths.', intro:'When side lengths are fractions, multiply the fraction lengths to find area.', steps:[{title:'Fraction × fraction',body:'Rectangle 2/3 × 3/4: A = 2/3 × 3/4 = 6/12 = 1/2.'},{title:'Use the area model',body:'Draw a grid subdivided by denominators.'},{title:'Mixed numbers',body:'1½ × 2½ = 3/2 × 5/2 = 15/4 = 3¾.'},{title:'Units',body:'Still square units — cm² or ft².'}], explanation:'Area of fractional rectangles motivates fraction multiplication.', exercises:[{question:'Rectangle ½ × ¾. Area?',answer:'3/8',hint:'1/2×3/4=3/8.'},{question:'Rectangle 1⅓ × 1½. Area?',answer:'2 sq units',hint:'4/3×3/2=12/6=2.'},{question:'Area=¾, length=½. Width?',answer:'3/2 = 1½',hint:'w=A÷l=3/4÷1/2=3/2.'}]},
  { id:'angles-measurement', title:'Drawing and Measuring Angles', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['angle','protractor','degree','draw','measure'], summary:'Use a protractor to measure and draw angles accurately.', intro:'Angles are measured in degrees using a protractor tool.', steps:[{title:'Zero the protractor',body:'Place center hole on vertex. Align 0° with one ray.'},{title:'Read the angle',body:'Follow the second ray to the scale.'},{title:'Estimate first',body:'Acute <90°, right=90°, obtuse 90-180°. Pick the right scale.'},{title:'Draw an angle',body:'Draw base ray. Mark the angle measure. Draw second ray through the mark.'}], explanation:'Accuracy requires identifying the correct scale (inner vs outer arc) on the protractor.', exercises:[{question:'Measure a right angle. Reading?',answer:'90°',hint:'Perfect corner.'},{question:'Draw a 150° angle. Obtuse or reflex?',answer:'Obtuse',hint:'90 < 150 < 180.'},{question:'Two angles form a straight line: one is 65°. Other?',answer:'115°',hint:'180-65=115.'}]},
  { id:'volume-packed-unit-cubes', title:'Volume by Packing Unit Cubes', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['volume','unit cubes','pack','layers','cubic units'], summary:'Find volume by counting unit cubes packed into a rectangular prism.', intro:'Volume = how many 1×1×1 unit cubes fit inside a solid.', steps:[{title:'Count base layer',body:'Base layer: 4×3=12 unit cubes.'},{title:'Count layers',body:'Prism is 4 layers tall: 12×4=48 unit cubes.'},{title:'Formula connection',body:'V=l×w×h=4×3×4=48.'},{title:'Why it works',body:'Volume = base area × height.'}], explanation:'Packing cubes makes the V=lwh formula intuitive — layers of the base.', exercises:[{question:'Base 5×4, height 3. Volume in unit cubes?',answer:'60',hint:'20×3=60.'},{question:'20 unit cubes in base, 5 layers. Total?',answer:'100',hint:'20×5.'},{question:'V=36 unit cubes, base 3×4. Height?',answer:'3',hint:'36÷12=3.'}]},
  { id:'place-value-millions', title:'Place Value to Millions', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['millions','place value','large numbers','periods'], summary:'Read and write numbers up to one million using place value.', intro:'Numbers have three-digit periods separated by commas: billions, millions, thousands, ones.', steps:[{title:'Place value chart',body:'Millions: 1,000,000. Hundred-thousands: 100,000. Ten-thousands: 10,000. Thousands: 1,000. Hundreds: 100. Tens: 10. Ones: 1.'},{title:'Write in standard form',body:'Four million, three hundred twenty thousand, five hundred one = 4,320,501.'},{title:'Comma placement',body:'Group into sets of 3 from right: 1,234,567.'},{title:'Word form',body:'Read each period separately: "four million, three hundred twenty thousand, five hundred one."'}], explanation:'The repeating pattern of hundreds-tens-ones within each period makes large numbers manageable.', exercises:[{question:'Value of 7 in 7,483,291.',answer:'7,000,000',hint:'7 is in the millions place.'},{question:'Write 3,052,400 in words.',answer:'Three million, fifty-two thousand, four hundred',hint:'Period by period.'},{question:'Write 5 million, 8 thousand, 9 in digits.',answer:'5,008,009',hint:'Fill zeros as placeholders.'}]},
  { id:'division-with-remainders', title:'Division with Remainders', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['remainder','divide','interpret','quotient','leftover'], summary:'Divide with remainders and interpret the remainder in context.', intro:'When a number does not divide evenly, the leftover is called the remainder.', steps:[{title:'Calculate',body:'25÷4=6 R1. 4×6=24. 25-24=1.'},{title:'Interpret the remainder',body:'"25 students into groups of 4. How many groups?" Answer: 6 groups (1 student left over).'},{title:'Round up when needed',body:'"25 students, buses fit 4. Buses needed?" 6R1→ need 7 buses (1 extra student).'},{title:'Ignore the remainder',body:'"How many complete groups?" → 6.'}], explanation:'Context determines whether to round up, down, or express remainder as a fraction.', exercises:[{question:'29 chairs, 6 per row. Full rows?',answer:'4 (with 5 left over)',hint:'29÷6=4R5.'},{question:'29 students, vans hold 8. Vans needed?',answer:'4 vans',hint:'29÷8=3R5. Round up to 4.'},{question:'27 cookies, 4 per bag. Bags if only full bags count?',answer:'6 bags',hint:'27÷4=6R3. Keep 6.'}]},
  { id:'order-decimals', title:'Ordering Decimals', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['decimals','order','compare','tenths','hundredths','thousandths'], summary:'Order a set of decimal numbers from least to greatest.', intro:'Line up decimals and compare place by place from left to right.', steps:[{title:'Line up decimal points',body:'Compare 3.4, 3.09, 3.45: align decimals.'},{title:'Fill in zeros',body:'3.40, 3.09, 3.45.'},{title:'Compare left to right',body:'All have 3 ones. Tenths: 4, 0, 4 → 3.09 is smallest.'},{title:'Final order',body:'3.09, 3.40, 3.45.'}], explanation:'Adding trailing zeros never changes a decimal\'s value but makes comparison easy.', exercises:[{question:'Order: 0.7, 0.07, 0.72.',answer:'0.07, 0.70, 0.72',hint:'Line up: tenths digit.'},{question:'Greatest of: 2.3, 2.35, 2.305.',answer:'2.35',hint:'2.300, 2.350, 2.305.'},{question:'Order 4 numbers: 1.8, 1.08, 1.81, 1.18.',answer:'1.08, 1.18, 1.8, 1.81',hint:'Compare tenths, then hundredths.'}]},
  { id:'powers-of-10', title:'Powers of 10', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['powers of ten','multiply by 10','divide by 10','place value','shift'], summary:'Multiply and divide by powers of 10 using place value shifting.', intro:'Multiplying by 10 shifts every digit one place to the left. Dividing shifts right.', steps:[{title:'Multiply by 10',body:'34×10=340. Append a zero (or shift digits left, add placeholder zero).'},{title:'Multiply by 100',body:'34×100=3400. Shift 2 places = 2 zeros.'},{title:'Divide by 10',body:'340÷10=34. Remove one zero.'},{title:'Decimals',body:'0.5×10=5. 5÷10=0.5. Decimal point shifts.'}], explanation:'The base-10 number system is built for this. Every multiplication/division by 10 is just a place value shift.', exercises:[{question:'456×100=?',answer:'45,600',hint:'Append 2 zeros.'},{question:'2300÷10=?',answer:'230',hint:'Remove one zero.'},{question:'0.07×1000=?',answer:'70',hint:'Shift 3 places right.'}]},
  { id:'roman-numerals', title:'Roman Numerals', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['Roman numerals','I V X L C D M','convert'], summary:'Read and write Roman numerals using the additive and subtractive systems.', intro:'Roman numerals use letters to represent values. They appear on clocks, buildings, and movie credits.', steps:[{title:'Symbols',body:'I=1, V=5, X=10, L=50, C=100, D=500, M=1000.'},{title:'Additive rule',body:'Write from largest to smallest, add values: VIII=8.'},{title:'Subtractive rule',body:'Smaller before larger = subtract. IV=4. IX=9. XL=40. XC=90.'},{title:'Convert',body:'1984: 1000+900+80+4 = MCMLXXXIV.'}], explanation:'Romans had no zero and multiplication was cumbersome — showing why positional notation (our system) was revolutionary.', exercises:[{question:'Convert XLVIII to standard form.',answer:'48',hint:'XL=40, VIII=8.'},{question:'Write 94 in Roman numerals.',answer:'XCIV',hint:'XC=90, IV=4.'},{question:'What year is MMXXV?',answer:'2025',hint:'MM=2000, XX=20, V=5.'}]},
  { id:'range-and-variability', title:'Range and Variability', grade:'35', gradeLabel:'3–5', subject:'statistics', tags:['range','variability','spread','maximum','minimum'], summary:'Calculate the range of a data set to measure spread.', intro:'The range shows how spread out data is. Range = maximum - minimum.', steps:[{title:'Find max and min',body:'Data: {8, 3, 15, 7, 12}. Max=15, min=3.'},{title:'Calculate range',body:'Range = 15-3 = 12.'},{title:'Interpret',body:'Large range = high variability. Small range = data is clustered.'},{title:'Outlier effect',body:'One extreme value increases range dramatically.'}], explanation:'Range is the simplest measure of spread. Standard deviation is a more sophisticated version.', exercises:[{question:'Data: 5,9,3,11,7. Range?',answer:'8',hint:'11-3=8.'},{question:'Data {20,21,22,23}. Range?',answer:'3',hint:'Small range = clustered.'},{question:'Adding 100 to dataset {3,5,7}. New range?',answer:'97',hint:'100-3=97.'}]},
  { id:'geometry-congruence-in-real-life', title:'Congruence in Real Life', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['congruent','real world','tile','manufacturing','same size'], summary:'Identify examples of congruent shapes in real-world contexts.', intro:'Congruence is everywhere: floor tiles, bricks, stamps, and coins are all congruent to their counterparts.', steps:[{title:'Same size AND shape',body:'Two floor tiles are congruent: same dimensions, same shape.'},{title:'Orientation does not matter',body:'A tile flipped or rotated is still congruent to the original.'},{title:'Why it matters',body:'Manufacturing requires congruent parts for interchangeability (e.g., screws, phone screens).'},{title:'Test for congruence',body:'If you can move/flip/rotate one shape to perfectly cover the other, they are congruent.'}], explanation:'Quality control in manufacturing is essentially checking for congruence within tolerance.', exercises:[{question:'Are two $1 coins congruent?',answer:'Yes — same size and shape.',hint:'Mass-produced coins.'},{question:'Floor tile 12"×12" and a phone screen 6"×4". Congruent?',answer:'No — different dimensions.',hint:'Congruent requires identical size and shape.'},{question:'Name 3 real-life examples of congruent objects.',answer:'Bricks, postage stamps, book pages — all mass produced',hint:'Any manufactured pair.'}]},
  { id:'basic-probability-outcomes', title:'Basic Probability', grade:'35', gradeLabel:'3–5', subject:'statistics', tags:['probability','likely','unlikely','certain','impossible','outcomes'], summary:'Describe likelihood of events using probability vocabulary.', intro:'Probability describes how likely an event is. We use words and fractions.', steps:[{title:'Probability vocabulary',body:'Impossible(0), unlikely, equally likely, likely, certain(1).'},{title:'Simple probability',body:'P(event) = favorable outcomes / total outcomes.'},{title:'Example',body:'Bag: 2 red, 8 blue. P(red)=2/10=1/5. Unlikely.'},{title:'Experimental vs theoretical',body:'Flip coin 10 times. Results may vary from 5/10. More flips → closer to 1/2.'}], explanation:'The law of large numbers: repeated experiments converge to theoretical probability.', exercises:[{question:'Bag: 5 yellow, 5 purple. P(yellow)?',answer:'1/2',hint:'5/10=1/2.'},{question:'Die: P(number >4)?',answer:'1/3',hint:'{5,6}=2 out of 6.'},{question:'P(rolling 7 on a normal die)?',answer:'0 — Impossible',hint:'A standard die only has 1-6.'}]},
  { id:'place-value-to-10000', title:'Place Value to 10,000', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['place value','thousands','ten-thousands','expanded form'], summary:'Read and write numbers to 10,000 using place value.', intro:'Beyond hundreds come thousands and ten-thousands.', steps:[{title:'Thousands',body:'1,000 to 9,000.'},{title:'Ten-thousands',body:'10,000. The number 10,000 has a 1 in the ten-thousands place.'},{title:'Expanded form',body:'6,348 = 6000+300+40+8.'},{title:'Compare large numbers',body:'Compare digit by digit from the highest place.'}], explanation:'Every fourth place follows the pattern: ones, tens, hundreds — then a new period begins.', exercises:[{question:'Value of 3 in 13,452.',answer:'3,000',hint:'Thousands place.'},{question:'Write expanded form: 8,307.',answer:'8000+300+7',hint:'No tens here.'},{question:'Compare: 9,874 __ 9,987.',answer:'<',hint:'Hundreds: 8 < 9.'}]},
  { id:'geometry-symmetry-rotational', title:'Rotational Symmetry', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['rotational symmetry','order','turn','center','rotation'], summary:'Identify rotational symmetry and find the order of rotation.', intro:'A shape has rotational symmetry if it looks the same after a rotation less than 360°.', steps:[{title:'Test for rotational symmetry',body:'Rotate the shape about its center. If it looks identical before full rotation, it has rotational symmetry.'},{title:'Order of rotation',body:'How many times does it repeat in 360°? Square: 4 times = order 4.'},{title:'Angle of rotation',body:'360° ÷ order. Square: 360÷4=90°.'},{title:'Examples',body:'Regular hexagon: order 6 (60°). Equilateral triangle: order 3 (120°). Circle: infinite.'}], explanation:'Rotational symmetry underlies crystal structures, wheels, and many logos.', exercises:[{question:'Order of rotational symmetry for a regular pentagon?',answer:'Order 5 (72°)',hint:'360÷5=72.'},{question:'Does a rectangle have rotational symmetry?',answer:'Yes — order 2 (180°)',hint:'Rectangle looks same after 180°.'},{question:'A shape has order 4. Rotation angle?',answer:'90°',hint:'360÷4=90.'}]},
  { id:'statistics-dot-plots', title:'Dot Plots', grade:'35', gradeLabel:'3–5', subject:'statistics', tags:['dot plot','frequency','data display','number line'], summary:'Create and analyze dot plots to display small data sets.', intro:'A dot plot places one dot above a number line for each data value.', steps:[{title:'Draw number line',body:'Mark all possible values along the number line.'},{title:'Plot dots',body:'Stack dots above each value as they occur.'},{title:'Analyze',body:'Tallest stack = mode. Spread = range. Where dots cluster = center.'},{title:'Compare',body:'Two dot plots side by side show differences in distribution.'}], explanation:'Dot plots are the simplest way to see the full shape of a small data set.', exercises:[{question:'Data: 3,4,4,5,5,5,6. Mode from dot plot?',answer:'5',hint:'Tallest stack.'},{question:'Cluster of dots over high values means?',answer:'Data tends to be large (right-skewed)',hint:'Clusters indicate where values concentrate.'},{question:'Range from dot plot spanning 4 to 11?',answer:'7',hint:'11-4=7.'}]},
  { id:'fraction-word-problems', title:'Fraction Word Problems', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['fraction','word problem','real life','add subtract multiply'], summary:'Solve word problems involving fractions.', intro:'Fraction word problems appear in cooking, measurement, and sharing.', steps:[{title:'Identify operation',body:'"Combined" or "total" → add. "Left over" → subtract. "Of" = multiply.'},{title:'Find common denominator if needed',body:'Adding/subtracting: find LCD first.'},{title:'Answer in context',body:'Include units and make sure answer is reasonable.'},{title:'Check by estimation',body:'1/3 + 2/3 should be close to 1. 1/2 of 8 = 4.'}], explanation:'Translating problem language into fraction operations is a key reasoning skill.', exercises:[{question:'Ran 2/5 mile in morning, 3/10 mile in afternoon. Total?',answer:'7/10 mile',hint:'LCD=10: 4/10+3/10.'},{question:'Pizza: 3/4 left. Eat 1/4 more. Remaining?',answer:'2/4=1/2',hint:'3/4-1/4=2/4.'},{question:'3/4 of 20 students passed. How many?',answer:'15',hint:'3/4×20=15.'}]},
  { id:'geometry-triangles-area', title:'Area of Triangles', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['triangle','area','base','height','formula'], summary:'Calculate the area of triangles using A = ½ × base × height.', intro:'Every triangle has exactly half the area of the rectangle enclosing it.', steps:[{title:'Identify base and height',body:'The height must be perpendicular to the base.'},{title:'Formula',body:'A = ½bh.'},{title:'Right triangles',body:'Legs are the base and height directly.'},{title:'Obtuse triangles',body:'Height may fall outside the triangle.'}], explanation:'Any triangle fits inside a parallelogram with exactly double its area. Halving gives the triangle formula.', exercises:[{question:'Base=8, height=5. Area?',answer:'20 sq units',hint:'½×8×5=20.'},{question:'Triangle area=30, base=10. Height?',answer:'6',hint:'30=½×10×h.'},{question:'Right triangle legs 6 and 8. Area?',answer:'24 sq units',hint:'½×6×8=24.'}]},
  { id:'algebra-patterns', title:'Algebraic Patterns and Sequences', grade:'35', gradeLabel:'3–5', subject:'algebra', tags:['patterns','algebra','sequence','predict','rule'], summary:'Identify rules and extend sequences.', intro:'An algebraic pattern follows a rule. Finding the rule lets you predict any term.', steps:[{title:'Find the common difference',body:'5,8,11,14: adds 3 each time. Arithmetic sequence.'},{title:'Write the rule',body:'nth term = 5+(n-1)×3 = 3n+2.'},{title:'Geometric patterns',body:'2,4,8,16: multiplies by 2. Geometric sequence.'},{title:'Use the rule to extend',body:'Rule=3n+2. 10th term=32.'}], explanation:'Recognizing patterns is a meta-skill that accelerates learning across all of mathematics.', exercises:[{question:'4,7,10,13,___',answer:'16',hint:'Add 3 each time.'},{question:'Rule: 4n+1. 5th term?',answer:'21',hint:'4(5)+1=21.'},{question:'3,6,12,24,___',answer:'48',hint:'Multiply by 2.'}]},
  { id:'negative-numbers-intro', title:'Negative Numbers Introduction', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['negative numbers','below zero','temperature','debt','number line'], summary:'Understand negative numbers in real-world contexts.', intro:'Negative numbers go below zero. They represent debt, temperature below 0°, or elevation below sea level.', steps:[{title:'Real contexts',body:'Temperature -10°C is 10° below zero. Debt of $5 = -$5.'},{title:'On the number line',body:'Negative numbers are to the left of 0. -3 is further left than -1.'},{title:'Ordering negatives',body:'-7 < -2 < 0 < 3. More negative = further left = smaller.'},{title:'Absolute value preview',body:'|-4| = 4: distance from zero ignores direction.'}], explanation:'Negative numbers complete the integers and allow subtraction to always have a result.', exercises:[{question:'Temperature is 4°C. Falls 9°. New temperature?',answer:'-5°C',hint:'4-9=-5.'},{question:'Order: -4, 2, -1, 0',answer:'-4,-1,0,2',hint:'Most negative first.'},{question:'Is -8 > -3?',answer:'No: -8 < -3',hint:'Further left = smaller.'}]},
  { id:'graphing-on-coordinate-plane-four-quads', title:'Four-Quadrant Coordinate Plane', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['coordinate plane','four quadrants','negative','plotting'], summary:'Plot and read points in all four quadrants of the coordinate plane.', intro:'The coordinate plane has four quadrants formed by the x and y axes.', steps:[{title:'Quadrant names',body:'QI: (+,+). QII: (-,+). QIII: (-,-). QIV: (+,-).'},{title:'Plot a point',body:'(-3, 2): move left 3, up 2. QII.'},{title:'Read a point',body:'Identify x (horizontal) then y (vertical) position.'},{title:'Reflections',body:'(3,4) reflected over y-axis: (-3,4).'}], explanation:'The full four-quadrant plane is needed for graphing functions and modeling all real phenomena.', exercises:[{question:'Plot (-2, -5). Quadrant?',answer:'QIII',hint:'Both negative.'},{question:'(4,3) reflected over x-axis.',answer:'(4,-3)',hint:'y changes sign.'},{question:'Distance from (0,0) to (-3,-4)?',answer:'5',hint:'√(9+16)=5.'}]},
  { id:'functions-table-graph', title:'Tables, Graphs and Functions', grade:'35', gradeLabel:'3–5', subject:'algebra', tags:['function','table','graph','rule','input output'], summary:'Connect tables, equations, and graphs to represent the same function.', intro:'Three representations of a function: a table, a graph, and an equation all describe the same relationship.', steps:[{title:'Table',body:'x:1,2,3. y:3,6,9. Pattern: y=3x.'},{title:'Equation',body:'y=3x.'},{title:'Graph',body:'Plot each (x,y) pair. Linear function → straight line.'},{title:'Check all three agree',body:'Point from table should fall on graph and satisfy equation.'}], explanation:'Multiple representations deepen understanding — weakness in one form can be offset by another.', exercises:[{question:'Table: (1,5),(2,7),(3,9). Equation?',answer:'y=2x+3',hint:'Each x increases by 1, y by 2.'},{question:'Equation y=x². When x=4, y=?',answer:'16',hint:'4²=16.'},{question:'Does (2,8) lie on y=3x+1?',answer:'No: 3(2)+1=7≠8',hint:'Substitute.'}]},
  { id:'fractions-in-recipes', title:'Fractions in Recipes and Measurement', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['fractions','cooking','recipes','double half'], summary:'Scale recipes up and down using fraction multiplication.', intro:'Recipes use fractions. Doubling or halving a recipe requires fraction multiplication.', steps:[{title:'Double a recipe',body:'¾ cup × 2 = 3/2 = 1½ cups.'},{title:'Halve a recipe',body:'¾ cup × ½ = 3/8 cup.'},{title:'Triple a recipe',body:'⅔ cup × 3 = 2 cups.'},{title:'Scale to n servings',body:'Multiply each ingredient by n/original servings.'}], explanation:'Scaling recipes is one of the most practical applications of fraction multiplication in everyday life.', exercises:[{question:'Recipe needs 2/3 cup sugar. Double it.',answer:'4/3 = 1⅓ cups',hint:'2/3×2=4/3.'},{question:'Recipe for 6 needs ¾ cup. Make 2 servings.',answer:'¼ cup',hint:'2/6×¾=2/8=1/4.'},{question:'3/4 cup flour per batch. 5 batches?',answer:'3¾ cups',hint:'5×3/4=15/4.'}]},
  { id:'divisibility-rules', title:'Divisibility Rules', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['divisibility','rules','2 3 4 5 6 9 10'], summary:'Use divisibility rules to quickly determine if a number divides evenly.', intro:'Divisibility rules let you test factors without actually dividing.', steps:[{title:'Div by 2',body:'Last digit is even.'},{title:'Div by 5',body:'Last digit 0 or 5.'},{title:'Div by 10',body:'Last digit 0.'},{title:'Div by 3',body:'Sum of digits divisible by 3. 123: 1+2+3=6 ✓'},{title:'Div by 9',body:'Sum of digits divisible by 9.'},{title:'Div by 4',body:'Last 2 digits divisible by 4.'}], explanation:'These rules come from properties of remainders in modular arithmetic.', exercises:[{question:'Is 846 divisible by 3?',answer:'Yes',hint:'8+4+6=18, divisible by 3.'},{question:'Is 732 divisible by 4?',answer:'Yes',hint:'Last 2 digits 32÷4=8.'},{question:'Is 9,045 divisible by 9?',answer:'Yes',hint:'9+0+4+5=18.'}]},
  { id:'writing-numbers-in-words', title:'Writing Numbers in Words', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['number words','write','read','period','standard form'], summary:'Write any number from words to digits and digits to words.', intro:'Standard form uses digits. Word form spells out the number using words.', steps:[{title:'Identify periods',body:'3,482,106: three million, four hundred eighty-two thousand, one hundred six.'},{title:'Read each period',body:'Read hundreds-tens-ones, then the period name: "four hundred eighty-two thousand."'},{title:'From words to digits',body:'"Two million, forty thousand, fifteen" = 2,040,015.'},{title:'Hyphen rule',body:'Hyphenate 21-99: twenty-one, forty-seven.'}], explanation:'Translating between forms deepens place-value understanding.', exercises:[{question:'Write 2,400,056 in words.',answer:'Two million, four hundred thousand, fifty-six',hint:'Period by period.'},{question:'Write in digits: fifty thousand, three.',answer:'50,003',hint:'No thousands? 0 in thousands place.'},{question:'Correct: seventy and two hundreds.',answer:'Two hundred seventy',hint:'In English, "and" is used only for a decimal point.'}]},
  { id:'fraction-strips', title:'Fraction Strips and Models', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['fraction strips','bar model','equivalent fractions','visual'], summary:'Use fraction strip models to compare and find equivalent fractions.', intro:'Fraction strips are folded paper bars showing fractions visually.', steps:[{title:'Build fraction strips',body:'One whole, folded into halves, thirds, fourths, sixths, eighths, twelfths.'},{title:'Line up strips',body:'Line up fractions to compare sizes.'},{title:'Find equivalents',body:'2/4 and 1/2 are the same length → equivalent.'},{title:'Add fractions',body:'Align strips end-to-end.'}], explanation:'Visual models build the deep understanding that justifies abstract rules.', exercises:[{question:'From a fraction strip, 2/6 = ?/3',answer:'1/3',hint:'Simplify by dividing by 2.'},{question:'Which is larger: 3/4 or 5/6?',answer:'5/6',hint:'6ths strip is smaller pieces; 5 of them > 3 of the larger 4ths.'},{question:'Show 1/2 + 1/4 with strips.',answer:'3/4',hint:'Line up 1/2 and 1/4 strips end-to-end.'}]},

  // ── Grades 6–8 ─────────────────────────────────────────────────────────────
  { id:'irrational-numbers', title:'Irrational Numbers', grade:'68', gradeLabel:'6–8', subject:'arithmetic', tags:['irrational','rational','real numbers','pi','sqrt2','decimal'], summary:'Distinguish rational and irrational numbers and locate irrationals on a number line.', intro:'Irrational numbers cannot be written as fractions. Their decimals never terminate or repeat.', steps:[{title:'Definition',body:'Rational: can write as p/q. Irrational: cannot. Examples: √2, π, e.'},{title:'Non-repeating non-terminating',body:'√2=1.41421356… never ends or repeats.'},{title:'Rational decimals',body:'1/3=0.333… (repeating). 1/4=0.25 (terminating). Both rational.'},{title:'On the number line',body:'√2≈1.414 — between 1 and 2, closer to √2 line.'}], explanation:'There are infinitely many irrationals between any two rationals. They fill the "holes" in the rational number line.', exercises:[{question:'Is 0.121212… rational or irrational?',answer:'Rational (0.12 repeating = 4/33)',hint:'Repeating decimal = rational.'},{question:'Classify √16.',answer:'Rational (=4)',hint:'√16=4=4/1.'},{question:'Is π rational or irrational?',answer:'Irrational',hint:'π=3.14159… never repeats.'}]},
  { id:'algebraic-proof-steps', title:'Justifying Steps in Algebra', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['algebraic proof','justify','property','reason'], summary:'Name the property that justifies each step in solving an equation.', intro:'Each step in solving an equation follows a property. Naming them builds mathematical reasoning.', steps:[{title:'Properties to cite',body:'Commutative, Associative, Distributive, Addition/Subtraction/Multiplication/Division Property of Equality, Identity, Inverse.'},{title:'Example',body:'Solve 3x+5=14. Step 1: subtract 5 (Subtraction Prop. of Equality). Step 2: divide by 3 (Division Prop. of Equality).'},{title:'Distributive property',body:'3(x+2)=3x+6: Distributive Property.'}], explanation:'Mathematical proof always requires justification — this is the entry-level form.', exercises:[{question:'3+x=3+x. Property?',answer:'Reflexive Property of Equality',hint:'Any value equals itself.'},{question:'If a=b then b=a. Property?',answer:'Symmetric Property',hint:'Equality works both ways.'},{question:'3(x+4)=3x+12. Property?',answer:'Distributive Property',hint:'a(b+c)=ab+ac.'}]},
  { id:'slope-from-graph', title:'Finding Slope from a Graph', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['slope','graph','rise run','read graph'], summary:'Calculate slope directly from a graph using rise over run.', intro:'On a graph, slope = rise/run = (vertical change)/(horizontal change) between any two points.', steps:[{title:'Pick two points',body:'Choose two clear lattice points on the line.'},{title:'Count rise',body:'Count how many units up (positive) or down (negative).'},{title:'Count run',body:'Count how many units right (positive).'},{title:'Simplify',body:'Rise=6, run=4. slope=6/4=3/2.'}], explanation:'Pick two points as far apart as possible for accuracy.', exercises:[{question:'Rise=4, run=2. Slope?',answer:'2',hint:'4÷2=2.'},{question:'Line goes down 3, right 6. Slope?',answer:'-1/2',hint:'-3/6=-1/2.'},{question:'Horizontal line. Slope?',answer:'0',hint:'No rise.'}]},
  { id:'writing-equations-two-step', title:'Writing Equations from Word Problems', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['equation','word problem','translate','variable'], summary:'Translate two-step word problems into equations and solve.', intro:'Setting up an equation is the key skill — solving it is mechanical after that.', steps:[{title:'Identify unknown',body:'Let x = the unknown.'},{title:'Translate relationships',body:'"5 more than 3 times a number is 20" → 3x+5=20.'},{title:'Solve the equation',body:'3x=15 → x=5.'},{title:'Answer in context',body:'"The number is 5."'}], explanation:'Equation-writing is the bridge between arithmetic reasoning and algebraic abstraction.', exercises:[{question:'"Twice a number minus 7 equals 11." Equation + solve.',answer:'2n-7=11; n=9',hint:'Add 7: 2n=18.'},{question:'"Total $47. Bought 3 items plus $5 shipping." Item price?',answer:'3x+5=47; x=$14',hint:'3x=42.'},{question:'"4 equal groups plus 3 extras = 19." Group size?',answer:'4n+3=19; n=4',hint:'4n=16.'}]},
  { id:'bivariate-data', title:'Bivariate Data Analysis', grade:'68', gradeLabel:'6–8', subject:'statistics', tags:['bivariate','two variables','scatter plot','association','trend'], summary:'Analyze relationships between two variables using scatter plots.', intro:'Bivariate data consists of pairs of measurements on two variables.', steps:[{title:'Plot ordered pairs',body:'Each data point is one observation of two variables.'},{title:'Describe association',body:'Direction: positive or negative. Strength: strong, moderate, weak. Shape: linear or curved.'},{title:'Outliers',body:'Points far from the cluster may be errors or unusual cases.'},{title:'Causation vs correlation',body:'Association does not imply causation.'}], explanation:'Correlation is quantified by r (-1 to 1). |r| near 1 = strong. |r| near 0 = weak.', exercises:[{question:'As hours increase, score increases. Association?',answer:'Positive',hint:'Both increase together.'},{question:'r=-0.85. Strong or weak?',answer:'Strong negative',hint:'|-0.85| is close to 1.'},{question:'Ice cream sales and sunburn rates are correlated. Causation?',answer:'No — both caused by hot weather (common cause)',hint:'Correlation ≠ causation.'}]},
  { id:'number-relationships-divisibility', title:'Number Relationships and Divisibility', grade:'68', gradeLabel:'6–8', subject:'arithmetic', tags:['divisibility','GCF','LCM','Venn diagram','number theory'], summary:'Find GCF and LCM using prime factorization and Venn diagrams.', intro:'GCF (greatest common factor) and LCM (least common multiple) are essential for fraction operations.', steps:[{title:'Prime factorize both',body:'12=2²×3. 18=2×3².'},{title:'GCF: shared factors',body:'GCF=2×3=6 (lowest power of each shared prime).'},{title:'LCM: all factors',body:'LCM=2²×3²=36 (highest power of each prime).'},{title:'GCF × LCM = product',body:'6×36=216=12×18 ✓'}], explanation:'GCF is used to simplify fractions. LCM is used to find common denominators.', exercises:[{question:'GCF of 30 and 45?',answer:'15',hint:'30=2×3×5. 45=3²×5. GCF=3×5=15.'},{question:'LCM of 8 and 12?',answer:'24',hint:'8=2³. 12=2²×3. LCM=2³×3=24.'},{question:'GCF×LCM for 10 and 15?',answer:'150 = 10×15',hint:'5×30=150.'}]},
  { id:'graphing-systems-solutions', title:'Graphing Systems of Equations', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['system of equations','graph','intersection','solution'], summary:'Solve systems of equations by graphing and finding the intersection.', intro:'The solution to a system is the point where the graphs intersect.', steps:[{title:'Graph each equation',body:'y=x+2 and y=-x+6. Graph both lines.'},{title:'Find intersection',body:'Lines cross at (2,4). Solution: x=2, y=4.'},{title:'Check',body:'(2,4): 4=2+2 ✓. 4=-2+6 ✓'},{title:'Special cases',body:'Parallel lines: no solution. Same line: infinite solutions.'}], explanation:'Graphing gives an approximate visual answer — algebra gives the exact one.', exercises:[{question:'Graph y=2x and y=-x+6. Intersection?',answer:'(2,4)',hint:'2x=-x+6 → 3x=6 → x=2.'},{question:'y=3 and y=5. Solution?',answer:'No solution — parallel horizontal lines.',hint:'Never intersect.'},{question:'y=x and y=x+1. Solution?',answer:'No solution — parallel lines.',hint:'Same slope, different intercept.'}]},
  { id:'comparing-populations', title:'Comparing Two Populations', grade:'68', gradeLabel:'6–8', subject:'statistics', tags:['compare populations','mean','median','variability','side by side'], summary:'Compare two data sets using measures of center and variability.', intro:'Use mean, median, and range (or IQR) to compare two populations.', steps:[{title:'Find center for each',body:'Mean or median for each group.'},{title:'Find spread',body:'Range or IQR for each.'},{title:'Overlap',body:'Do distributions overlap heavily? Less overlap = bigger difference.'},{title:'Relative difference',body:'Difference in means relative to spread.'}], explanation:'Statistical comparison requires considering both center AND spread.', exercises:[{question:'A: mean=60, B: mean=70. Which is higher?',answer:'B has higher average',hint:'70>60.'},{question:'A: range=5, B: range=20. More consistent?',answer:'A is more consistent',hint:'Smaller range = less spread.'},{question:'Both have same mean but different range. What does this mean?',answer:'Same center, different spread — one is more variable',hint:'Variability matters too.'}]},
  { id:'function-rate-of-change', title:'Rate of Change in Functions', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['rate of change','linear','slope','table','function'], summary:'Calculate and interpret rate of change from tables and equations.', intro:'Rate of change tells how much y changes per unit change in x. It equals slope for linear functions.', steps:[{title:'From a table',body:'Δy/Δx. If x goes 1→3 and y goes 2→8: (8-2)/(3-1)=3.'},{title:'From equation',body:'y=5x+1: rate of change = coefficient of x = 5.'},{title:'Constant rate',body:'Linear functions have constant rate of change (slope).'},{title:'Non-constant rate',body:'Nonlinear functions have varying rate of change.'}], explanation:'Rate of change is the foundation of calculus, linking algebra to continuous change.', exercises:[{question:'Table: x:0,1,2. y:3,7,11. Rate of change?',answer:'4',hint:'(11-3)/(2-0)=4.'},{question:'y=6x-2. Rate of change?',answer:'6',hint:'Coefficient of x.'},{question:'y=x². Rate of change from x=2 to x=4?',answer:'(16-4)/(4-2)=6',hint:'Not constant — it is a nonlinear function.'}]},
  { id:'transformational-geometry', title:'Congruence via Transformations', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['congruence','transformation','translation','rotation','reflection','rigid motion'], summary:'Define congruence through rigid transformations (rotations, reflections, translations).', intro:'Two figures are congruent if one can be obtained from the other by a sequence of rigid motions.', steps:[{title:'Rigid motions preserve size',body:'Translation (slide), rotation (turn), reflection (flip) — none stretch or shrink.'},{title:'Compose transformations',body:'Reflect then translate: a combined rigid motion.'},{title:'Congruence test',body:'If you can find rigid motions mapping figure A to figure B, they are congruent.'},{title:'Orientation',body:'Translations and rotations preserve orientation. Reflections reverse it.'}], explanation:'This definition of congruence is more powerful and general than the side-angle approach.', exercises:[{question:'Translate (2,3) by (4,-1). New point?',answer:'(6,2)',hint:'Add vectors.'},{question:'Is a rotation a rigid motion?',answer:'Yes — preserves distances and angles.',hint:'No stretching.'},{question:'Reflect (-2,5) over y-axis.',answer:'(2,5)',hint:'x changes sign.'}]},
  { id:'pythagorean-theorem-proof-informal', title:'Informal Proof of Pythagorean Theorem', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['Pythagorean','proof','area','squares on sides'], summary:'Understand why a²+b²=c² through area arguments.', intro:'The Pythagorean theorem can be proven by rearranging areas.', steps:[{title:'Draw squares on each side',body:'Draw a square on each side of a right triangle. Area of square = side².'},{title:'Area sum argument',body:'The two smaller squares together fill exactly the large square.'},{title:'Geometric proof sketch',body:'Cut the two legs\' squares into pieces. Rearrange inside the hypotenuse square. They fit perfectly.'},{title:'Confirm with numbers',body:'3-4-5: 9+16=25=5².'}], explanation:'There are over 370 known proofs of the Pythagorean theorem. President Garfield discovered one in 1876.', exercises:[{question:'Square areas 36 and 64 on the two legs. Hypotenuse?',answer:'10',hint:'√(36+64)=√100=10.'},{question:'Is this theorem about area or length?',answer:'Both — c²=a²+b² relates areas of squares; c relates lengths.',hint:'The equation involves squares of lengths.'},{question:'3-4-5 check: 3²+4²=?',answer:'25=5²',hint:'9+16=25.'}]},
  { id:'percent-error', title:'Percent Error', grade:'68', gradeLabel:'6–8', subject:'arithmetic', tags:['percent error','estimation','measurement','accuracy'], summary:'Calculate percent error to measure accuracy of estimates and measurements.', intro:'Percent error compares the difference between a measured value and the true value.', steps:[{title:'Formula',body:'%Error = |measured-true|/true × 100.'},{title:'Example',body:'Estimated 50, actual 60: |50-60|/60 × 100 = 16.7%.'},{title:'Interpret',body:'Lower % = more accurate estimate.'},{title:'Vs percent change',body:'Percent change: (new-old)/old. Percent error: |measured-actual|/actual.'}], explanation:'Percent error quantifies accuracy in science experiments and manufacturing.', exercises:[{question:'Estimate 45, actual 50. % error?',answer:'10%',hint:'|45-50|/50×100=10.'},{question:'Measure 9.8 cm, actual 10 cm. % error?',answer:'2%',hint:'0.2/10×100.'},{question:'% error 5%, actual value 80. Measured value?',answer:'76 or 84',hint:'0.05×80=4. 80±4.'}]},
  { id:'compound-interest', title:'Compound Interest', grade:'68', gradeLabel:'6–8', subject:'arithmetic', tags:['compound interest','principal','rate','time','exponential growth'], summary:'Calculate compound interest using the formula A=P(1+r/n)^(nt).', intro:'Compound interest earns interest on previous interest — money grows exponentially.', steps:[{title:'Formula',body:'A=P(1+r/n)^(nt). P=principal, r=annual rate, n=compounds/year, t=years.'},{title:'Example: annual compounding',body:'$1000 at 5%, 3 years: A=1000(1.05)³=$1157.63.'},{title:'Compare frequencies',body:'More compounding periods → more interest.'},{title:'vs simple interest',body:'Simple: A=P(1+rt). Compound always grows faster.'}], explanation:'Einstein allegedly called compound interest the "eighth wonder of the world."', exercises:[{question:'$500, 4%, annually, 5 yrs.',answer:'$608.33',hint:'500(1.04)⁵≈608.33.'},{question:'$1000, 6%, semi-annually, 2 yrs.',answer:'$1126.16',hint:'1000(1.03)⁴≈1126.16.'},{question:'Simple vs compound: $200 at 5% for 3 years.',answer:'Simple=$230. Compound≈$231.53',hint:'Simple: 200×1.15. Compound: 200(1.05)³.'}]},
  { id:'inequalities-real-world', title:'Inequalities in Real-World Contexts', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['inequalities','word problems','constraint','real world'], summary:'Write and solve inequalities from real-world constraints.', intro:'Many real-world situations involve constraints: "at most," "at least," "no more than."', steps:[{title:'Key phrases',body:'"At least" → ≥. "At most" → ≤. "More than" → >. "Fewer than" → <.'},{title:'Write the inequality',body:'"Must earn at least $200": E ≥ 200.'},{title:'Solve if needed',body:'"At most 12 items at $3 each, $40 budget": 3n ≤ 40 → n ≤ 13.3, so n ≤ 13.'},{title:'Interpret',body:'Integer constraint: round toward feasible side.'}], explanation:'Mathematical modeling with inequalities describes budgets, safety limits, and manufacturing tolerances.', exercises:[{question:'"Need at least 70 to pass. Got 58 more than base." Write inequality.',answer:'58+b ≥ 70 → b ≥ 12',hint:'"At least 70" means ≥70.'},{question:'"Earn at most 40 hrs at $12/hr." Max earning?',answer:'$480',hint:'12×40=480.'},{question:'"Ride at least 48 inches tall." Kid is 45". Eligible?',answer:'No: 45 < 48',hint:'Inequality check.'}]},
  { id:'geometry-volume-composite', title:'Volume of Composite Solids', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['composite solid','volume','add subtract','prism','cylinder'], summary:'Find the volume of composite solids by adding or subtracting simpler solid volumes.', intro:'Complex solids are combinations of prisms, cylinders, cones, and spheres.', steps:[{title:'Identify component solids',body:'A swimming pool = rectangular prism. A silo = cylinder + cone.'},{title:'Calculate each volume',body:'Use V=lwh, V=πr²h, V=⅓πr²h, V=⁴⁄₃πr³ as appropriate.'},{title:'Add or subtract',body:'Cylinder with cone cap: add volumes. Cylinder with hole bored out: subtract cylinder hole.'},{title:'Units',body:'All in cubic units.'}], explanation:'Composite solid volume is a core skill in engineering design.', exercises:[{question:'Prism 4×3×5 with cone hole r=1, h=5. Volume?',answer:'V=60-5π/3≈54.76',hint:'Subtract cone from prism.'},{question:'Cylinder r=3, h=10 topped with hemisphere r=3. Volume?',answer:'90π+18π=108π≈339.3',hint:'Hemi=⅔πr³.'},{question:'Two cubes: 3³+2³. Total volume?',answer:'27+8=35 cubic units',hint:'Sum of two separate volumes.'}]},
  { id:'non-linear-functions-tables', title:'Non-Linear Functions from Tables', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['nonlinear','quadratic','exponential','rate of change','table'], summary:'Distinguish linear from nonlinear functions using tables.', intro:'In a linear function, rate of change is constant. Nonlinear functions have changing rates of change.', steps:[{title:'Calculate successive Δy/Δx',body:'x:0,1,2,3. y:0,1,4,9. Δy: 1,3,5. Δy/Δx not constant → nonlinear (quadratic).'},{title:'Graph shape',body:'Linear: straight line. Quadratic: parabola. Exponential: curve.'}], explanation:'The second differences being constant identifies a quadratic function.', exercises:[{question:'y: 1,2,4,8. Linear?',answer:'No — ratio is constant (×2), not difference → exponential',hint:'Δy: 1,2,4 — not constant.'},{question:'y: 5,8,11,14. Linear?',answer:'Yes — Δy=3 constant.',hint:'Constant difference.'},{question:'y: 0,1,4,9,16. Type?',answer:'Quadratic (y=x²)',hint:'Perfect squares.'}]},

  // ── Grades 9–12 ────────────────────────────────────────────────────────────
  { id:'solving-quadratics-factoring', title:'Solving Quadratics by Factoring', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['quadratic','factoring','zero product','roots'], summary:'Solve quadratic equations by factoring and applying the Zero Product Property.', intro:'If a product equals zero, at least one factor must be zero.', steps:[{title:'Write in standard form',body:'x²+3x-10=0.'},{title:'Factor',body:'(x+5)(x-2)=0.'},{title:'Zero Product Property',body:'x+5=0 → x=-5. x-2=0 → x=2.'},{title:'Check',body:'(-5)²+3(-5)-10=25-15-10=0 ✓'}], explanation:'Zero Product Property: ab=0 implies a=0 or b=0. Only works when one side = 0.', exercises:[{question:'x²-x-12=0',answer:'x=4 or x=-3',hint:'(x-4)(x+3)=0.'},{question:'x²=9',answer:'x=3 or x=-3',hint:'x²-9=0. (x-3)(x+3)=0.'},{question:'2x²+5x-3=0',answer:'x=1/2 or x=-3',hint:'(2x-1)(x+3)=0.'}]},
  { id:'right-triangle-special-angles', title:'Special Right Triangles (30-60-90 and 45-45-90)', grade:'912', gradeLabel:'9–12', subject:'trigonometry', tags:['30-60-90','45-45-90','special right triangle','ratio'], summary:'Use special right triangle ratios to find exact side lengths.', intro:'30-60-90 and 45-45-90 triangles have fixed side ratios that give exact values.', steps:[{title:'45-45-90 ratios',body:'Legs: 1:1. Hypotenuse: √2. If leg=5: hyp=5√2.'},{title:'30-60-90 ratios',body:'Short leg:long leg:hyp = 1:√3:2. If short leg=3: long=3√3, hyp=6.'},{title:'From hypotenuse',body:'45-45-90: leg=hyp/√2=hyp√2/2.'},{title:'From long leg (30-60-90)',body:'Short leg = long/√3. Hyp = 2×short.'}], explanation:'These ratios come from geometry, not a calculator. They give exact answers.', exercises:[{question:'45-45-90, leg=7. Hypotenuse?',answer:'7√2',hint:'Multiply leg by √2.'},{question:'30-60-90, short leg=4. Long leg and hypotenuse?',answer:'4√3 and 8',hint:'×√3 and ×2.'},{question:'30-60-90, hyp=10. Short leg?',answer:'5',hint:'Short leg = hyp/2.'}]},
  { id:'statistics-distributions', title:'Shape of Distributions', grade:'912', gradeLabel:'9–12', subject:'statistics', tags:['distribution','symmetric','skewed','uniform','bell curve'], summary:'Describe and classify the shape of data distributions.', intro:'The shape of a distribution reveals how data is spread and where the center lies.', steps:[{title:'Symmetric',body:'Data mirrors itself about the center. Mean ≈ median.'},{title:'Skewed right (positive)',body:'Long tail on the right. Mean > median. Income distributions.'},{title:'Skewed left (negative)',body:'Long tail on the left. Mean < median.'},{title:'Uniform',body:'All values equally likely. Mean = median = midpoint.'},{title:'Bimodal',body:'Two peaks = two modes. May indicate two subpopulations.'}], explanation:'Knowing shape determines which summary statistics are most appropriate.', exercises:[{question:'Mean > median. Likely shape?',answer:'Skewed right',hint:'High outliers pull mean up.'},{question:'Test scores near perfect: 95,96,97,98. Shape?',answer:'Skewed left (ceiling effect)',hint:'Low tail, high cluster.'},{question:'Normal distribution: mean or median better for center?',answer:'Both — they are equal',hint:'Symmetric → mean=median.'}]},
  { id:'absolute-value-inequalities', title:'Absolute Value Inequalities', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['absolute value','inequality','compound','and or','number line'], summary:'Solve absolute value inequalities by writing compound inequalities.', intro:'|x|<a means "distance from 0 is less than a": -a<x<a. |x|>a means x>a or x<-a.', steps:[{title:'|x|<a case (AND)',body:'|x|<5 → -5<x<5.'},{title:'|x|>a case (OR)',body:'|x|>5 → x>5 or x<-5.'},{title:'With expression',body:'|2x-3|≤7 → -7≤2x-3≤7 → -2≤x≤5.'},{title:'Graph',body:'AND: segment. OR: two rays.'}], explanation:'The "and" vs "or" determines the solution structure — visualize as a distance problem.', exercises:[{question:'|x|<4',answer:'-4<x<4',hint:'Distance from 0 less than 4.'},{question:'|x-2|>3',answer:'x>5 or x<-1',hint:'-3<x-2<3 flipped.'},{question:'|3x|≤9',answer:'-3≤x≤3',hint:'-9≤3x≤9.'}]},
  { id:'regression-analysis', title:'Regression Analysis', grade:'912', gradeLabel:'9–12', subject:'statistics', tags:['regression','least squares','r squared','residuals','predict'], summary:'Perform and interpret linear regression analysis.', intro:'Regression finds the best-fit line and quantifies how well it fits.', steps:[{title:'Residual',body:'Residual = actual y - predicted ŷ. Positive = point above line.'},{title:'Sum of squared residuals',body:'Least squares minimizes the sum of squared residuals.'},{title:'r²',body:'r²=0.81: 81% of variation in y is explained by x. Higher = better fit.'},{title:'Residual plot',body:'Good fit: random scatter in residual plot. Pattern = bad fit (try different model).'}], explanation:'r² is the coefficient of determination. It is the square of the correlation coefficient r.', exercises:[{question:'ŷ=3x+2. Actual y=14, x=4. Residual?',answer:'0',hint:'ŷ=3(4)+2=14. 14-14=0.'},{question:'r=0.9. r²=?',answer:'0.81',hint:'0.9²=0.81.'},{question:'Residual plot shows a curve. What does this suggest?',answer:'Linear model is not the best fit; try quadratic or other',hint:'Non-random pattern signals model mismatch.'}]},
  { id:'parametric-equations', title:'Parametric Equations', grade:'912', gradeLabel:'9–12', subject:'precalculus', tags:['parametric','parameter','eliminate','curve','motion'], summary:'Write and graph parametric equations, then eliminate the parameter.', intro:'Parametric equations define x and y separately as functions of a third variable (parameter) t.', steps:[{title:'Parametric form',body:'x=f(t), y=g(t). Example: x=t+1, y=t².'},{title:'Table of values',body:'Choose t values, compute x and y, plot (x,y).'},{title:'Eliminate parameter',body:'x=t+1 → t=x-1. Sub into y: y=(x-1)². Standard form.'},{title:'Motion interpretation',body:'t=time: parametric traces a path as t increases.'}], explanation:'Parametric equations describe motion, projectiles, and curves not expressible as y=f(x).', exercises:[{question:'x=2t, y=t². Eliminate parameter.',answer:'y=x²/4',hint:'t=x/2. y=(x/2)².'},{question:'x=cos t, y=sin t. Eliminate parameter.',answer:'x²+y²=1 (circle)',hint:'cos²t+sin²t=1.'},{question:'Projectile: x=30t, y=40t-5t². Shape?',answer:'Parabola',hint:'Eliminate t from x=30t → t=x/30.'}]},
  { id:'number-theory-modular', title:'Modular Arithmetic', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['modular arithmetic','mod','remainder','clock','congruence'], summary:'Perform arithmetic in a modular system and solve congruences.', intro:'Modular arithmetic deals with remainders. 17 mod 5 = 2 because 17 = 3×5 + 2.', steps:[{title:'Definition',body:'a ≡ b (mod n) means n divides (a-b). "a and b have the same remainder when divided by n."'},{title:'Clock arithmetic',body:'Clock is mod 12: 10+5=3 (mod 12).'},{title:'Arithmetic rules',body:'Add/multiply modularly: (a+b) mod n = ((a mod n)+(b mod n)) mod n.'},{title:'Applications',body:'ISBN codes, credit card checksums, cryptography.'}], explanation:'RSA encryption is built on modular exponentiation with very large primes.', exercises:[{question:'23 mod 7 = ?',answer:'2',hint:'23=3×7+2.'},{question:'(15+9) mod 6 = ?',answer:'0',hint:'24 mod 6=0.'},{question:'Day of week arithmetic: Wednesday + 10 days = ?',answer:'Saturday',hint:'(3+10) mod 7=6=Saturday.'}]},
  { id:'sequences-recursive', title:'Recursive Sequences', grade:'912', gradeLabel:'9–12', subject:'precalculus', tags:['recursive','Fibonacci','sequence','formula','previous term'], summary:'Define sequences recursively and compute terms from recursive formulas.', intro:'A recursive formula defines each term based on previous terms.', steps:[{title:'Recursive notation',body:'a₁=2, aₙ=aₙ₋₁+5. a₂=7, a₃=12, …'},{title:'Fibonacci',body:'F₁=1, F₂=1, Fₙ=Fₙ₋₁+Fₙ₋₂. 1,1,2,3,5,8,13,21…'},{title:'Convert to explicit',body:'aₙ=a₁+(n-1)d for arithmetic, aₙ=a₁rⁿ⁻¹ for geometric.'},{title:'Computer science connection',body:'Recursive sequences mirror recursive algorithms.'}], explanation:'The Fibonacci sequence appears in nature: sunflower seeds, nautilus shells, and rabbit populations.', exercises:[{question:'a₁=3, aₙ=2aₙ₋₁. Find a₄.',answer:'24',hint:'3,6,12,24.'},{question:'Fibonacci: F₇=?',answer:'13',hint:'1,1,2,3,5,8,13.'},{question:'aₙ=aₙ₋₁+4, a₁=5. Explicit formula?',answer:'aₙ=4n+1',hint:'Arithmetic with d=4.'}]},
  { id:'trig-addition-formulas', title:'Trigonometric Addition Formulas', grade:'912', gradeLabel:'9–12', subject:'trigonometry', tags:['addition formula','sin(A+B)','cos(A+B)','sum difference'], summary:'Apply the sine and cosine addition formulas.', intro:'sin(A+B) and cos(A+B) expand in terms of sin and cos of A and B separately.', steps:[{title:'Sine addition',body:'sin(A+B)=sin A cos B + cos A sin B.'},{title:'Cosine addition',body:'cos(A+B)=cos A cos B - sin A sin B.'},{title:'Subtraction',body:'sin(A-B)=sin A cos B - cos A sin B. cos(A-B)=cos A cos B + sin A sin B.'},{title:'Apply: sin(75°)',body:'sin(45°+30°)=sin45°cos30°+cos45°sin30°=(√6+√2)/4.'}], explanation:'These formulas derive all other trig identities, including double-angle formulas.', exercises:[{question:'sin(90°) using sin(60°+30°).',answer:'1',hint:'sin60cos30+cos60sin30=(√3/2)(√3/2)+(1/2)(1/2)=3/4+1/4=1.'},{question:'cos(A-B): A=B. Simplify.',answer:'cos(0)=1 → cos²A+sin²A=1 ✓',hint:'Pythagorean identity.'},{question:'sin(A+B): A=B.',answer:'sin(2A)=2sinAcosA',hint:'Double angle formula!'}]},
  { id:'area-under-curve', title:'Area Between Curves', grade:'912', gradeLabel:'9–12', subject:'calculus', tags:['area between curves','integral','subtract','definite integral'], summary:'Find the area between two curves using definite integrals.', intro:'The area between f(x) and g(x) on [a,b] is ∫|f(x)-g(x)|dx.', steps:[{title:'Identify top and bottom functions',body:'If f(x)≥g(x) on [a,b], area=∫[a to b](f(x)-g(x))dx.'},{title:'Find intersection points',body:'Set f(x)=g(x) to find limits a and b.'},{title:'Integrate the difference',body:'Area=∫₀² (4-x²)dx=[4x-x³/3]₀²=8-8/3=16/3.'},{title:'Check sign',body:'If curves cross, split into sub-intervals.'}], explanation:'This concept is fundamental to probability (area under density curve = probability).', exercises:[{question:'Area between y=4 and y=x². Intersect at x=±2.',answer:'16/3≈5.33 per side → total 32/3',hint:'∫₋₂² (4-x²)dx.'},{question:'Area between y=x and y=x². Intersect at 0 and 1.',answer:'1/6',hint:'∫₀¹(x-x²)dx=[x²/2-x³/3]₀¹=1/6.'},{question:'Why do we subtract functions?',answer:'Difference of top and bottom gives the vertical height at each x',hint:'Think of thin vertical strips.'}]},
  { id:'differential-equations-intro', title:'Introduction to Differential Equations', grade:'912', gradeLabel:'9–12', subject:'calculus', tags:['differential equations','separable','dy/dx','ODE','initial value'], summary:'Solve simple separable differential equations.', intro:'A differential equation relates a function to its derivative.', steps:[{title:'Recognize separable form',body:'dy/dx = f(x)g(y) → separate variables.'},{title:'Separate',body:'dy/g(y) = f(x)dx.'},{title:'Integrate both sides',body:'∫dy/g(y) = ∫f(x)dx + C.'},{title:'Apply initial condition',body:'Use a given point to find C.'}], explanation:'Most physical laws (Newton\'s, radioactive decay, population growth) are differential equations.', exercises:[{question:'dy/dx=2x. Solve.',answer:'y=x²+C',hint:'Integrate both sides.'},{question:'dy/dx=y. Solve.',answer:'y=Ce^x',hint:'dy/y=dx → ln|y|=x → y=Ce^x.'},{question:'dy/dx=3y, y(0)=5. Solve.',answer:'y=5e^(3x)',hint:'y=Ce^(3x). At x=0: C=5.'}]},
  { id:'linear-transformations', title:'Linear Transformations', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['linear transformation','matrix','vector','transform','scale rotate'], summary:'Understand linear transformations as matrix multiplications.', intro:'A linear transformation maps vectors to vectors in a consistent, linear way.', steps:[{title:'Matrix multiplication as transformation',body:'T(v)=Av. Each input vector maps to an output vector.'},{title:'Common transformations',body:'Rotation 90°: [0,-1;1,0]. Reflection over x-axis: [1,0;0,-1]. Scale by 2: [2,0;0,2].'},{title:'Apply',body:'Rotate (3,2) by 90°: [0,-1;1,0][3;2]=[−2;3].'}], explanation:'All of computer graphics, robotics, and ML use matrix linear transformations.', exercises:[{question:'Scale matrix 3×3 applied to (2,4).',answer:'(6,12)',hint:'[3,0;0,3][2;4]=[6;12].'},{question:'Reflect (5,-3) over x-axis.',answer:'(5,3)',hint:'[1,0;0,-1][5;-3]=[5;3].'},{question:'90° CCW rotation of (1,0).',answer:'(0,1)',hint:'[0,-1;1,0][1;0]=[0;1].'}]},
  { id:'probability-conditional', title:'Conditional Probability', grade:'912', gradeLabel:'9–12', subject:'statistics', tags:['conditional probability','P(A|B)','Bayes','given','dependent'], summary:'Calculate conditional probabilities and apply Bayes\' theorem.', intro:'P(A|B) is the probability of A given that B has already occurred.', steps:[{title:'Formula',body:'P(A|B) = P(A∩B)/P(B).'},{title:'Example',body:'P(rain)=0.4. P(cold|rain)=0.7. P(cold and rain)=0.4×0.7=0.28.'},{title:'Bayes\' theorem',body:'P(A|B) = P(B|A)×P(A)/P(B). Update beliefs with evidence.'},{title:'Independence',body:'A⊥B if P(A|B)=P(A). Knowing B gives no info about A.'}], explanation:'Bayes\' theorem is the foundation of Bayesian statistics, spam filters, and medical testing.', exercises:[{question:'P(A∩B)=0.12, P(B)=0.4. P(A|B)?',answer:'0.3',hint:'0.12/0.4=0.3.'},{question:'P(B|A)=0.8, P(A)=0.25, P(B)=0.5. P(A|B)?',answer:'0.4',hint:'0.8×0.25/0.5=0.4.'},{question:'If P(A|B)=P(A), are A and B independent?',answer:'Yes',hint:'Definition of independence.'}]},
];